import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  getDocs,
  limit,
  onSnapshot,
  orderBy,
  query,
  setDoc,
  where,
  type Unsubscribe
} from "firebase/firestore";

import { getFirebaseDb } from "@/lib/firebase/client";
import type { Product } from "@/lib/products/types";

export function listenVisibleProducts(onData: (products: Product[]) => void, onError?: () => void) {
  const db = getFirebaseDb();
  if (!db) return null;

  const q = query(
    collection(db, "products"),
    where("visible", "==", true),
    orderBy("updatedAt", "desc"),
    limit(200)
  );

  const unsub: Unsubscribe = onSnapshot(
    q,
    (snap) => {
      const products: Product[] = snap.docs.map((d) => {
        const data = d.data() as Omit<Product, "id">;
        return { id: d.id, ...data };
      });
      onData(products);
    },
    () => onError?.()
  );

  return unsub;
}

export function listenAllProducts(onData: (products: Product[]) => void, onError?: () => void) {
  const db = getFirebaseDb();
  if (!db) return null;

  const q = query(collection(db, "products"), orderBy("updatedAt", "desc"), limit(500));

  const unsub: Unsubscribe = onSnapshot(
    q,
    (snap) => {
      const products: Product[] = snap.docs.map((d) => ({
        id: d.id,
        ...(d.data() as Omit<Product, "id">)
      }));
      onData(products);
    },
    () => onError?.()
  );

  return unsub;
}

export async function listAllProducts() {
  const db = getFirebaseDb();
  if (!db) return [] as Product[];
  const snap = await getDocs(query(collection(db, "products"), orderBy("updatedAt", "desc")));
  return snap.docs.map((d) => ({ id: d.id, ...(d.data() as Omit<Product, "id">) }));
}

export async function upsertProduct(product: Omit<Product, "id"> & { id?: string }) {
  const db = getFirebaseDb();
  if (!db) throw new Error("Firestore not configured");

  const now = Date.now();
  const payload = { ...product, updatedAt: now, createdAt: product.createdAt ?? now };
  if (product.id) {
    await setDoc(doc(db, "products", product.id), payload, { merge: true });
    return product.id;
  }
  const created = await addDoc(collection(db, "products"), payload);
  return created.id;
}

export async function deleteProduct(productId: string) {
  const db = getFirebaseDb();
  if (!db) throw new Error("Firestore not configured");
  await deleteDoc(doc(db, "products", productId));
}

